import{_ as t,o as e,c as a,Q as o}from"./chunks/framework.b67c47e6.js";const b=JSON.parse('{"title":"Integrations & Webhooks","description":"","frontmatter":{},"headers":[],"relativePath":"guide/integrations/index.md","filePath":"guide/integrations/index.md","lastUpdated":1784186850000}'),n={name:"guide/integrations/index.md"},s=o('<h1 id="integrations-webhooks" tabindex="-1">Integrations &amp; Webhooks <a class="header-anchor" href="#integrations-webhooks" aria-label="Permalink to &quot;Integrations &amp; Webhooks&quot;">​</a></h1><p>Webhooks let you receive automatic notifications in external systems when specific events occur in produuz.it.</p><nav class="table-of-contents"><ul><li><a href="#how-webhooks-work">How Webhooks Work</a></li><li><a href="#event-types">Event Types</a></li><li><a href="#configuring-a-webhook">Configuring a Webhook</a></li><li><a href="#custom-payload-fields">Custom Payload Fields</a></li><li><a href="#authentication">Authentication</a></li><li><a href="#watching-users">Watching Users</a></li><li><a href="#use-cases">Use Cases</a></li></ul></nav><h2 id="how-webhooks-work" tabindex="-1">How Webhooks Work <a class="header-anchor" href="#how-webhooks-work" aria-label="Permalink to &quot;How Webhooks Work&quot;">​</a></h2><p>When a configured event happens (e.g., a constructible is marked as ready), produuz.it sends an HTTP POST request to your specified URL with event data in the payload.</p><h2 id="event-types" tabindex="-1">Event Types <a class="header-anchor" href="#event-types" aria-label="Permalink to &quot;Event Types&quot;">​</a></h2><table><thead><tr><th>Event</th><th>Triggered When</th></tr></thead><tbody><tr><td><strong>Constructible Start</strong></td><td>A constructible begins production (first station started).</td></tr><tr><td><strong>Constructible Ready</strong></td><td>A constructible completes all production stations.</td></tr><tr><td><strong>Station Ready</strong></td><td>A specific station is marked as completed for a constructible.</td></tr><tr><td><strong>Report Deprecation</strong></td><td>A report&#39;s underlying design data has been updated.</td></tr></tbody></table><h2 id="configuring-a-webhook" tabindex="-1">Configuring a Webhook <a class="header-anchor" href="#configuring-a-webhook" aria-label="Permalink to &quot;Configuring a Webhook&quot;">​</a></h2><table><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>URL</strong></td><td>The endpoint that will receive the POST request.</td></tr><tr><td><strong>Event type</strong></td><td>Which event triggers this webhook.</td></tr><tr><td><strong>Payload fields</strong></td><td>Which data fields to include in the request body.</td></tr><tr><td><strong>Production line</strong></td><td>Optionally scope the webhook to a specific production line.</td></tr><tr><td><strong>Auth method</strong></td><td>Authentication type (Bearer token, API key, etc.).</td></tr><tr><td><strong>Secret</strong></td><td>Shared secret for request signing or authentication.</td></tr><tr><td><strong>Custom headers</strong></td><td>Additional HTTP headers to include with each request.</td></tr><tr><td><strong>Custom payload fields</strong></td><td>Additional name/value fields added to the request body, alongside the standard payload.</td></tr></tbody></table><h2 id="custom-payload-fields" tabindex="-1">Custom Payload Fields <a class="header-anchor" href="#custom-payload-fields" aria-label="Permalink to &quot;Custom Payload Fields&quot;">​</a></h2><p>Beyond the standard payload fields, you can add your own name/value pairs that are merged into the request body of every request this webhook sends. This is useful for constants your endpoint expects — a plant identifier, a routing key, an environment tag, etc.</p><p>Each field has a <strong>name</strong> (the JSON key) and a <strong>value</strong> (a text string). The fields are added alongside the standard payload data. If a custom field uses the same name as a standard field, the standard field is kept.</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>You can secure your webhook endpoint by configuring:</p><ul><li><strong>Auth header</strong> — Adds an <code>Authorization</code> header with your chosen method and secret.</li><li><strong>Custom headers</strong> — Add any additional headers your endpoint requires.</li></ul><h2 id="watching-users" tabindex="-1">Watching Users <a class="header-anchor" href="#watching-users" aria-label="Permalink to &quot;Watching Users&quot;">​</a></h2><p>Assign users to &quot;watch&quot; a webhook. Watching users receive in-app notifications when the webhook fires, in addition to the external HTTP request.</p><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li><strong>ERP integration</strong> — Sync production status to your business system.</li><li><strong>Label printing</strong> — Trigger label printing when a constructible is ready (see <a href="/tutorials/nicelabel/">NiceLabel tutorial</a>).</li><li><strong>Notifications</strong> — Send alerts to Slack, Teams, or other messaging platforms.</li><li><strong>Quality tracking</strong> — Log production events in external quality management systems.</li></ul>',19),r=[s];function i(d,h,l,c,u,g){return e(),a("div",null,r)}const f=t(n,[["render",i]]);export{b as __pageData,f as default};
